#include <stdio.h>
#include <string.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <time.h>
#include <errno.h>

int main(void) {
    struct mq_attr attr = { .mq_maxmsg = 10, .mq_msgsize = 128 };
    mqd_t mq = mq_open("/kf_mq_timeout", O_CREAT | O_RDWR, 0644, &attr);

    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);

    char buf[128];
    ssize_t n = mq_timedreceive(mq, buf, sizeof(buf), NULL, &ts);
    if (n == -1 && errno == ETIMEDOUT)
        printf("Timeout: no message\n");

    mq_send(mq, "timed msg", 9, 0);
    clock_gettime(CLOCK_REALTIME, &ts);
    ts.tv_sec += 5;
    n = mq_timedreceive(mq, buf, sizeof(buf), NULL, &ts);
    buf[n] = '\0';
    printf("Received: %s\n", buf);

    mq_close(mq);
    mq_unlink("/kf_mq_timeout");
    return 0;
}

