void example_timed(void) {
    struct mq_attr a = { .mq_maxmsg = 1, .mq_msgsize = 64 };
    mqd_t q = mq_open("/kf_ex_timed", O_CREAT|O_RDWR, 0644, &a);
    mq_send(q, "fill", 4, 0);
    struct timespec ts; clock_gettime(CLOCK_REALTIME, &ts);
    int r = mq_timedsend(q, "full", 4, 0, &ts);
    if (r == -1 && errno == ETIMEDOUT)
        printf("Send timed out (queue full)\n");
    char buf[64]; mq_receive(q, buf, sizeof(buf), NULL);
    mq_close(q); mq_unlink("/kf_ex_timed");
}
